import { banks, Bank } from '@/constants/banks';

// Xây dựng Index (O(1) Lookup Table) để tăng tốc độ tra cứu
const binIndex: Record<string, Bank> = {};
const shortNameIndex: Record<string, Bank> = {};

for (const bank of banks) {
  binIndex[bank.bin] = bank;
  shortNameIndex[bank.shortName.toLowerCase()] = bank;
}

/**
 * Lấy thông tin ngân hàng qua mã BIN (O(1))
 */
export function getBankByBin(bin: string): Bank | undefined {
  return binIndex[bin];
}

/**
 * Lấy thông tin ngân hàng qua mã Tên viết tắt (shortName) (O(1))
 */
export function getBankByShortName(shortName: string): Bank | undefined {
  if (!shortName) return undefined;
  return shortNameIndex[shortName.toLowerCase()];
}
